CustomField.formula:
/* Donor Icon */ IF( AND(npo02__TotalOppAmount__c>0, npo02__TotalOppAmount__c<$Setup.NPBP_Options__c.Major_Donor_Threshold__c), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Donations_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Account_Donations_Report_ID__c,15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/Donor.png","Donor",35, 35),"")+ " ", NULL)+
/* Major Donor Icon */ IF( npo02__TotalOppAmount__c>=$Setup.NPBP_Options__c.Major_Donor_Threshold__c, HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Donations_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Account_Donations_Report_ID__c,15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/Major.png","Major Donor",35, 35)+ " ",""), NULL)+
/* Grantmaking Icon */ IF( npsp__Grantmaker__c = TRUE, HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Grants_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Account_Grants_Report_ID__c,15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/Grantmaker.png","Grant Maker",35, 35)+ " ",""), NULL)+
/* Matching Gifts Icon */ IF( npsp__Matching_Gift_Company__c = TRUE, HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Matching_Gifts_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Account_Matching_Gifts_Report_ID__c,15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/Matching.png","Matching Gifts",35, 35)+ " ",""), NULL)+
/* Current Membership Icon */ IF(npo02__MembershipEndDate__c >= TODAY(), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Memberships_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Account_Memberships_Report_ID__c, 15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/Member.png","Member",35, 35)+ " ",""),NULL)+
/* Lapsed Membership Icon */ IF(npo02__MembershipEndDate__c<TODAY(), HYPERLINK(IF($User.UIThemeDisplayed = "Theme4d", "/one/one.app#/sObject/" & $Setup.NPBP_Options__c.Account_Memberships_Report_ID__c & "/view?&fv0="+Id, "/" & LEFT($Setup.NPBP_Options__c.Contact_Memberships_Report_ID__c, 15) & "?pv0="+Id), IMAGE("/resource/Impact_Icons/FormerMember.png","Past Member",35, 35)+ " ",""),NULL)
